import java.awt.image.*;
import java.awt.*;
public class ScaleImage {
    public static void main(String[] args) {
        BufferedImage original = new BufferedImage(100, 100, BufferedImage.TYPE_INT_RGB);
        int newW = original.getWidth() / 2;
        int newH = original.getHeight() / 2;
        BufferedImage scaled = new BufferedImage(newW, newH, BufferedImage.TYPE_INT_RGB);
        Graphics2D g = scaled.createGraphics();
        g.drawImage(original, 0, 0, newW, newH, null);
        g.dispose();
        System.out.println(scaled.getWidth());
        System.out.println(scaled.getHeight());
        System.out.println(original.getWidth());
    }
}
